package main

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

// healthHandler handles the /healthz endpoint.
func healthHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Fprintln(w, "OK")
}

func main() {
	// Handle SIGTERM from gracefully shutting down
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGTERM)

	// Define context with a timeout (e.g., 5 seconds)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	// Create a simple HTTP server with the healthz handler
	http.HandleFunc("/healthz", healthHandler)
	fmt.Println("Starting server on :8080")

	// Serve HTTP on :8080
	srv := &http.Server{
		Addr:    ":8080",
		Handler: nil, // nil means "everything"
	}

	go func() {
		// Run the server in a goroutine
		if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			fmt.Printf("HTTP Server error: %s\n", err)
		}
	}()

	// Wait for SIGTERM and gracefully close the server
	<-quit
	fmt.Println("Received SIGTERM, starting graceful shutdown...")

	// Gracefully shutdown the server
	// New context with a timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	srv.Shutdown(ctx)

	fmt.Println("HTTP server has shut down.")
}
